import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { ProductoService } from '../../services/producto.service';
import { Producto } from '../../models/producto.model';

@Component({
  selector: 'app-producto-detalle',
  templateUrl: './producto-detalle.component.html',
  styleUrls: ['./producto-detalle.component.css']
})
export class ProductoDetalleComponent implements OnInit {
  producto?: Producto;
  cargando = true;
  error = '';

  constructor(private route: ActivatedRoute, private productoService: ProductoService) { }

  ngOnInit(): void {
    const id = Number(this.route.snapshot.paramMap.get('id'));
    this.productoService.getById(id).subscribe({
      next: (data) => { this.producto = data; this.cargando = false; },
      error: (err) => { this.error = 'Error al cargar el producto.'; this.cargando = false; }
    });
  }
}
<div class="container mt-4">
  <div *ngIf="cargando" class="text-center"><div class="spinner-border text-primary"></div></div>
  <div *ngIf="error" class="alert alert-danger">{{ error }}</div>
  <div *ngIf="producto && !cargando" class="row">
    <div class="col-md-6">
      <img [src]="producto.imagenUrl || 'assets/placeholder.jpg'" class="img-fluid rounded" alt="{{ producto.nombre }}">
    </div>
    <div class="col-md-6">
      <h2>{{ producto.nombre }}</h2>
      <p class="text-muted"><i class="bi bi-tag"></i> {{ producto.categoria?.nombre || 'Sin categoría' }}</p>
      <hr><p>{{ producto.descripcion }}</p>
      <h3 class="text-primary">{{ producto.precio | currency:'EUR' }}</h3>
      <div class="mb-3">
        <span class="badge bg-success" *ngIf="producto.stock > 0"><i class="bi bi-check-circle"></i> En stock: {{ producto.stock }}</span>
        <span class="badge bg-danger" *ngIf="producto.stock === 0"><i class="bi bi-x-circle"></i> Sin stock</span>
      </div>
      <div class="d-grid gap-2">
        <button class="btn btn-primary btn-lg" [disabled]="producto.stock === 0"><i class="bi bi-cart-plus"></i> Añadir al Carrito</button>
        <button class="btn btn-outline-secondary" routerLink="/productos"><i class="bi bi-arrow-left"></i> Volver</button>
      </div>
    </div>
  </div>
</div>
